"use client";

import Link from "next/link";
import { Bell, MessageSquare, Plus, Search, Menu, X } from "lucide-react";
import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useAuthStore } from "@/store/auth.store";
import { useNotificationsStore } from "@/store/notifications.store";
import { useChatStore } from "@/store/chat.store";
import { Button } from "@/components/ui/button";
import { getInitials } from "@/lib/utils";

export function Header() {
  const { user, clearAuth } = useAuthStore();
  const unreadNotifs = useNotificationsStore((s) => s.unreadCount);
  const conversations = useChatStore((s) => s.conversations);
  const unreadMessages = conversations.reduce((sum, c) => sum + c.unread_count, 0);
  const [mobileOpen, setMobileOpen] = useState(false);

  return (
    <header className="sticky top-0 z-50 w-full border-b border-[var(--color-border)] bg-[var(--color-void)]/90 backdrop-blur-xl">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 h-16 flex items-center justify-between gap-4">
        {/* Logo */}
        <Link href="/main" className="flex items-center gap-2 shrink-0 group">
          <div className="w-8 h-8 bg-amber-500 rounded-[6px] flex items-center justify-center">
            <span className="font-display text-black text-sm tracking-wider">CB</span>
          </div>
          <span className="font-display text-xl tracking-widest hidden sm:block group-hover:text-amber-400 transition-colors">
            CARSANDBIKES
          </span>
        </Link>

        {/* Search bar - desktop */}
        <Link
          href="/main/listings"
          className="hidden md:flex flex-1 max-w-md items-center gap-2 h-9 px-3 rounded-[var(--radius-md)] bg-[var(--color-elevated)] border border-[var(--color-border)] text-[var(--color-text-muted)] text-sm hover:border-[var(--color-text-muted)] transition-colors"
        >
          <Search className="h-4 w-4 shrink-0" />
          <span>Search vehicles…</span>
        </Link>

        {/* Actions */}
        <div className="flex items-center gap-1">
          {user ? (
            <>
              <Link href="/main/listings/new">
                <Button variant="primary" size="sm" className="hidden sm:flex gap-1">
                  <Plus className="h-4 w-4" />
                  Sell
                </Button>
              </Link>

              {/* Chat */}
              <Link href="/main/chat" className="relative p-2 rounded-[var(--radius-md)] hover:bg-[var(--color-elevated)] transition-colors">
                <MessageSquare className="h-5 w-5 text-[var(--color-text-secondary)]" />
                {unreadMessages > 0 && (
                  <span className="absolute top-1 right-1 h-4 w-4 rounded-full bg-amber-500 text-black text-[10px] font-bold flex items-center justify-center">
                    {unreadMessages > 9 ? "9+" : unreadMessages}
                  </span>
                )}
              </Link>

              {/* Notifications */}
              <Link href="/main/notifications" className="relative p-2 rounded-[var(--radius-md)] hover:bg-[var(--color-elevated)] transition-colors">
                <Bell className="h-5 w-5 text-[var(--color-text-secondary)]" />
                {unreadNotifs > 0 && (
                  <span className="absolute top-1 right-1 h-4 w-4 rounded-full bg-amber-500 text-black text-[10px] font-bold flex items-center justify-center relative badge-pulse">
                    {unreadNotifs > 9 ? "9+" : unreadNotifs}
                  </span>
                )}
              </Link>

              {/* Avatar */}
              <button
                className="ml-1 h-8 w-8 rounded-full bg-amber-500/20 border border-amber-500/30 flex items-center justify-center text-amber-400 text-xs font-bold hover:bg-amber-500/30 transition-colors"
                onClick={() => clearAuth()}
                title="Sign out"
              >
                {getInitials(user.full_name)}
              </button>
            </>
          ) : (
            <>
              <Link href="/auth/login">
                <Button variant="ghost" size="sm">Sign in</Button>
              </Link>
              <Link href="/auth/register">
                <Button variant="primary" size="sm">Join free</Button>
              </Link>
            </>
          )}

          {/* Mobile menu toggle */}
          <button
            className="md:hidden p-2 text-[var(--color-text-secondary)]"
            onClick={() => setMobileOpen((o) => !o)}
            aria-label="Toggle menu"
          >
            {mobileOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
          </button>
        </div>
      </div>

      {/* Mobile menu */}
      <AnimatePresence>
        {mobileOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: "auto" }}
            exit={{ opacity: 0, height: 0 }}
            className="md:hidden border-t border-[var(--color-border)] bg-[var(--color-surface)]"
          >
            <nav className="p-4 flex flex-col gap-2">
              <Link href="/main/listings" className="px-3 py-2 rounded-[var(--radius-md)] hover:bg-[var(--color-elevated)] text-[var(--color-text-secondary)] hover:text-[var(--color-text-primary)] transition-colors" onClick={() => setMobileOpen(false)}>
                Browse Vehicles
              </Link>
              {user && (
                <Link href="/main/listings/new" className="px-3 py-2 rounded-[var(--radius-md)] bg-amber-500 text-black font-medium text-center" onClick={() => setMobileOpen(false)}>
                  + Sell Vehicle
                </Link>
              )}
            </nav>
          </motion.div>
        )}
      </AnimatePresence>
    </header>
  );
}
